output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?attendance WHERE {
  ?series wdt:P31 wd:Q13322454 .
  ?game wdt:P121 ?series .
  {
    ?game wdt:P1371 wd:Q24730 ; wdt:P1372 wd:Q520466 .
  } UNION {
    ?game wdt:P1371 wd:Q520466 ; wdt:P1372 wd:Q24730 .
  }
  ?game wdt:P1158 ?attendance .
}
ORDER BY DESC(?attendance)
LIMIT 1

